import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import axios from 'axios';

const StudyRoom = ({ task }) => {
    const { id } = useParams();
    const navigate = useNavigate();
    
    // Timer State (e.g., 25 minutes)
    const [seconds, setSeconds] = useState(1);
    const [isActive, setIsActive] = useState(false);

    // Timer Logic
    useEffect(() => {
        let interval = null;
        if (isActive && seconds > 0) {
            interval = setInterval(() => {
                setSeconds((prev) => prev - 1);
            }, 1000);
        } else if (seconds === 0) {
            clearInterval(interval);
            alert("Study session over! Time to check progress.");
        }
        return () => clearInterval(interval);
    }, [isActive, seconds]);

    const formatTime = (secs) => {
        const mins = Math.floor(secs / 60);
        const remainingSecs = secs % 60;
        return `${mins}:${remainingSecs < 10 ? '0' : ''}${remainingSecs}`;
    };

    const handleFinish = async (isCompleted) => {
        try {
            const status = isCompleted ? 'completed' : 'missed';
            await axios.patch(`/api/tasks/${id}`, { status }, {
                headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
            });
            navigate('/planPage');
        } catch (error) {
            console.error("Error updating task:", error);
        }
    };

    return (
        <div className="study-room-container" style={{ padding: '20px', textAlign: 'center' }}>
            <h2>Topic: {task?.title || "Loading..."}</h2>

            {/* Video Section */}
            <div className="video-section" style={{ marginBottom: '20px' }}>
                <iframe
                    width="560"
                    height="315"
                    src={`https://www.youtube.com/embed?listType=search&list=${task?.title}+tutorial`}
                    title="Study Video"
                    frameBorder="0"
                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                    allowFullScreen
                ></iframe>
            </div>

            {/* Timer Section */}
            <div className="timer-section" style={{ fontSize: '2rem', margin: '20px' }}>
                <div className="timer-display">{formatTime(seconds)}</div>
                <button onClick={() => setIsActive(!isActive)}>
                    {isActive ? 'Pause' : 'Start Focus Timer'}
                </button>
                <button onClick={() => setSeconds(25 * 60)}>Reset</button>
            </div>

            {/* Completion Controls */}
            <div className="controls" style={{ marginTop: '30px' }}>
                <button 
                    onClick={() => handleFinish(true)} 
                    style={{ backgroundColor: 'green', color: 'white', marginRight: '10px' }}
                >
                    Finish Day (Completed)
                </button>
                <button 
                    onClick={() => handleFinish(false)} 
                    style={{ backgroundColor: 'red', color: 'white' }}
                >
                    Not Finished (Reschedule)
                </button>
            </div>
        </div>
    );
};

export default StudyRoom;
